prompt --application/pages/page_00003
begin
wwv_flow_imp_page.create_page(
 p_id=>3
,p_name=>'Detalle Bar'
,p_alias=>'DETALLE-BAR'
,p_step_title=>'Detalle Bar'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'const API_BASE = ''https://parranderos-api-3clz.onrender.com/api/bares'';',
'const barId = parseInt(apex.item(''P3_BAR_ID'').getValue());',
'',
'function cargarComentarios() {',
'  fetch(`${API_BASE}/${barId}/comentarios`)',
'    .then(res => res.json())',
'    .then(data => {',
'      const container = document.getElementById(''comentarios-container'');',
'      if (data.length === 0) {',
unistr('        container.innerHTML = ''<p>No hay comentarios a\00FAn. \00A1S\00E9 el primero!</p>'';'),
'        return;',
'      }',
'      container.innerHTML = data.map(c => `',
'        <div style="border:1px solid #ddd; border-radius:8px; padding:12px; margin-bottom:10px;">',
unistr('          <strong>${c.autor || ''An\00F3nimo''}</strong>'),
'          <span style="color:#888; font-size:0.85em; margin-left:10px;">',
'            ${c.fecha ? new Date(c.fecha).toLocaleDateString(''es-CO'') : ''''}',
'          </span>',
'          <p style="margin-top:6px;">${c.texto}</p>',
'        </div>',
'      `).join('''');',
'    })',
'    .catch(err => {',
'      document.getElementById(''comentarios-container'').innerHTML =',
'        ''<p style="color:red;">Error cargando comentarios.</p>'';',
'    });',
'}',
'',
'cargarComentarios();',
'',
'function enviarComentario() {',
'  const texto = document.getElementById(''P3_TEXTO_COMENTARIO'').value;',
'  if (!texto.trim()) {',
unistr('    apex.message.showErrors([{ message: ''El comentario no puede estar vac\00EDo.'' }]);'),
'    return;',
'  }',
'  fetch(`${API_BASE}/${barId}/comentarios`, {',
'    method: ''POST'',',
'    headers: { ''Content-Type'': ''application/json'' },',
'    body: JSON.stringify({',
'      bar_id: parseInt(barId),',
'      texto: texto,',
'      autor: apex.env.APP_USER',
'    })',
'  })',
'  .then(res => res.json())',
'  .then(() => {',
'    document.getElementById(''P3_TEXTO_COMENTARIO'').value = '''';',
'    cargarComentarios();',
'  })',
'  .catch(() => {',
'    apex.message.showErrors([{ message: ''Error enviando el comentario.'' }]);',
'  });',
'}',
'',
'document.getElementById(''btn-enviar-comentario'').addEventListener(''click'', enviarComentario);',
'',
'function cargarEventos() {',
'  fetch(`${API_BASE}/${barId}/eventos`)',
'    .then(res => res.json())',
'    .then(data => {',
'      const container = document.getElementById(''eventos-container'');',
'      if (data.length === 0) {',
unistr('        container.innerHTML = ''<p>No hay eventos a\00FAn.</p>'';'),
'        return;',
'      }',
'      container.innerHTML = data.map(e => {',
'        const campos = Object.entries(e)',
'          .filter(([k]) => ![''bar_id'',''nombre'',''fecha_creacion''].includes(k))',
'          .map(([k,v]) => `<span style="margin-right:12px;"><strong>${k}:</strong> ${v}</span>`)',
'          .join('''');',
'        return `',
'          <div style="border:1px solid #ddd; border-radius:8px; padding:12px; margin-bottom:10px;">',
'            <strong style="font-size:1.1em;">${e.nombre}</strong><br/>',
'            <div style="margin-top:6px; color:#555;">${campos}</div>',
'          </div>`;',
'      }).join('''');',
'    })',
'    .catch(() => {',
'      document.getElementById(''eventos-container'').innerHTML =',
'        ''<p style="color:red;">Error cargando eventos.</p>'';',
'    });',
'}',
'',
'function enviarEvento() {',
'  const nombre = document.getElementById(''EVT_NOMBRE'').value;',
'  if (!nombre.trim()) {',
'    apex.message.showErrors([{ message: ''El nombre del evento es obligatorio.'' }]);',
'    return;',
'  }',
'  const evento = { nombre: nombre };',
'  const label1 = document.getElementById(''EVT_CAMPO1_LABEL'').value.trim();',
'  const valor1 = document.getElementById(''EVT_CAMPO1_VALOR'').value.trim();',
'  const label2 = document.getElementById(''EVT_CAMPO2_LABEL'').value.trim();',
'  const valor2 = document.getElementById(''EVT_CAMPO2_VALOR'').value.trim();',
'  if (label1 && valor1) evento[label1] = valor1;',
'  if (label2 && valor2) evento[label2] = valor2;',
'',
'  fetch(`${API_BASE}/${barId}/eventos`, {',
'    method: ''POST'',',
'    headers: { ''Content-Type'': ''application/json'' },',
'    body: JSON.stringify(evento)',
'  })',
'  .then(res => res.json())',
'  .then(() => {',
'    document.getElementById(''EVT_NOMBRE'').value = '''';',
'    document.getElementById(''EVT_CAMPO1_LABEL'').value = '''';',
'    document.getElementById(''EVT_CAMPO1_VALOR'').value = '''';',
'    document.getElementById(''EVT_CAMPO2_LABEL'').value = '''';',
'    document.getElementById(''EVT_CAMPO2_VALOR'').value = '''';',
'    cargarEventos();',
'  })',
'  .catch(() => {',
'    apex.message.showErrors([{ message: ''Error registrando el evento.'' }]);',
'  });',
'}',
'',
'cargarEventos();',
'document.getElementById(''btn-enviar-evento'').addEventListener(''click'', enviarEvento);'))
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'03'
,p_last_updated_by=>'CO_B331_SQL_S60_ADMIN'
,p_last_upd_yyyymmddhh24miss=>'20260517043150'
);
